import mysql.connector
import os

def validate_file_path(file_path):
    # Validate the file path to ensure it is a CSV file and exists
    if not file_path.lower().endswith('.csv'):
        raise ValueError("Only CSV files are allowed.")
    if not os.path.isfile(file_path):
        raise FileNotFoundError("The specified file does not exist.")
    return file_path

def load_data_infile(file_path, table_name, db_config):
    try:
        # Validate the file path
        validated_file_path = validate_file_path(file_path)

        # Establish a database connection
        connection = mysql.connector.connect(**db_config)
        cursor = connection.cursor()

        # Enable local_infile
        cursor.execute("SET GLOBAL local_infile = 1")

        # Use parameterized query to prevent SQL injection
        query = "LOAD DATA INFILE %s INTO TABLE {} FIELDS TERMINATED BY ',' ENCLOSED BY '\"' LINES TERMINATED BY '\n' IGNORE 1 ROWS".format(table_name)
        cursor.execute(query, (validated_file_path,))

        # Commit the transaction
        connection.commit()

    except mysql.connector.Error as err:
        print(f"Error: {err}")
    finally:
        if connection.is_connected():
            cursor.close()
            connection.close()

